import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Cache Aside、Read Through、Write Through 与多级缓存","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"cache-patterns"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/02-cache-patterns-multilevel.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/02-cache-patterns-multilevel.md","lastUpdated":null}'),l={name:"05-backend-data/notes/07-cache-messaging-storage/02-cache-patterns-multilevel.md"};function n(r,a,h,d,o,p){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="cache-aside、read-through、write-through-与多级缓存" tabindex="-1">Cache Aside、Read Through、Write Through 与多级缓存 <a class="header-anchor" href="#cache-aside、read-through、write-through-与多级缓存" aria-label="Permalink to &quot;Cache Aside、Read Through、Write Through 与多级缓存&quot;">​</a></h1><p>缓存模式规定读取、写入、失效和故障时谁负责协调缓存与事实源。正确选择来自一致性要求、数据重建成本、访问分布和故障预算；缓存不能替代数据库约束和授权判断。</p><h2 id="_1-缓存命中路径的代价模型" tabindex="-1">1. 缓存命中路径的代价模型 <a class="header-anchor" href="#_1-缓存命中路径的代价模型" aria-label="Permalink to &quot;1. 缓存命中路径的代价模型&quot;">​</a></h2><p>一次读取的期望延迟近似为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E(latency) = hit_rate × cache_latency</span></span>
<span class="line"><span>           + miss_rate × (cache_latency + source_latency + fill_cost)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这只是均值模型。生产决策还要看 p95/p99、缓存客户端排队、序列化、网络跨区、回源并发和缓存故障。命中率 95% 并不自动代表收益：剩余 5% 若集中同时 miss，可能击穿数据库。</p><p>缓存对象必须有事实来源和重建路径。用户余额、库存、授权和幂等唯一性可缓存用于读取，但最终判定仍在事务/受控策略系统。</p><h2 id="_2-cache-aside-旁路缓存" tabindex="-1">2. Cache Aside（旁路缓存） <a class="header-anchor" href="#_2-cache-aside-旁路缓存" aria-label="Permalink to &quot;2. Cache Aside（旁路缓存）&quot;">​</a></h2><p>应用同时认识缓存和数据库。读取流程：先缓存，miss 后查数据库、序列化、写缓存、返回。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant C as Client</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant A as Application</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant R as Redis</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant D as Database</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;A: GET product</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A-&gt;&gt;R: GET key</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    alt hit</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        R--&gt;&gt;A: cached value</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    else miss</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        R--&gt;&gt;A: nil</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        A-&gt;&gt;D: SELECT current row</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        D--&gt;&gt;A: authoritative value</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        A-&gt;&gt;R: SET value EX ttl</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    end</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A--&gt;&gt;C: response</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>写入常用“先提交数据库，再删除缓存”：</p><ol><li>在数据库事务验证并提交新值。</li><li>提交成功后删除缓存 key。</li><li>下一次读取回源并填充新值。</li></ol><p>先更新缓存再写数据库会在数据库失败时暴露不存在的事实。先删除缓存再更新数据库存在竞态：请求 A 删除，读请求 B 读旧数据库并回填，A 随后提交，新缓存继续旧值。</p><p>即使“提交后删除”也可能删除失败，或旧 miss 在提交前读旧值、却在提交后最后回填。需要 TTL、版本化 key、延迟二次删除、CDC/事件失效或 compare-version fill 来限制窗口。</p><h3 id="适用与代价" tabindex="-1">适用与代价 <a class="header-anchor" href="#适用与代价" aria-label="Permalink to &quot;适用与代价&quot;">​</a></h3><p>优点：简单、只缓存真正读取的数据、应用能控制对象形态。缺点：每个调用方容易实现不同规则，miss 路径复杂，写/删竞态要显式治理。</p><h2 id="_3-read-through" tabindex="-1">3. Read Through <a class="header-anchor" href="#_3-read-through" aria-label="Permalink to &quot;3. Read Through&quot;">​</a></h2><p>应用只向缓存/缓存库请求；缓存层 miss 时调用 loader 读取事实源并保存。形式可以是客户端库、本地代理或托管缓存能力。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>value, err := productCache.Get(ctx, key, func(ctx context.Context) (Product, error) {</span></span>
<span class="line"><span>    return repository.GetProduct(ctx, tenantID, productID)</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>loader 必须接受请求 deadline、限制同 key 并发、区分 not found 与暂时错误、控制序列化版本。缓存层若是独立服务，不应获得过宽数据库权限；跨服务 loader 也不能绕过租户授权。</p><p>Read Through 集中重复逻辑，但会隐藏回源延迟。调用方仍需知道缓存可能返回稍旧数据和 loader 错误。不是所有 Redis 产品原生替应用访问任意数据库；大多数工程中的 read-through 是应用库模式。</p><h2 id="_4-write-through" tabindex="-1">4. Write Through <a class="header-anchor" href="#_4-write-through" aria-label="Permalink to &quot;4. Write Through&quot;">​</a></h2><p>应用写缓存接口，缓存层同步写事实源，只有两边按约定完成才返回。它让读缓存保持热，但普通 Redis 与 PostgreSQL 之间没有天然原子事务。</p><p>失败组合：</p><ul><li>数据库成功、缓存失败：事实已提交，客户端看到失败并可能重试。</li><li>缓存成功、数据库失败：若先发布缓存，新值不具备事实。</li><li>响应丢失：客户端不知道是否提交。</li></ul><p>实现应把数据库作为提交点：服务事务写事实与 outbox，缓存更新是可重试投影；若必须同步更新，失败时使缓存 entry 不可见/删除，而不是回滚不了的数据库写。所谓 write-through 不能掩盖跨系统双写问题。</p><h2 id="_5-write-behind-write-back" tabindex="-1">5. Write Behind / Write Back <a class="header-anchor" href="#_5-write-behind-write-back" aria-label="Permalink to &quot;5. Write Behind / Write Back&quot;">​</a></h2><p>先接受缓存写，异步批量落事实源，能降低写延迟和合并热点计数，但缓存成为暂时事实来源。需要持久日志、序列号、幂等、重放、背压、对账、故障转移和数据损失预算。</p><p>适合可丢或可重建的遥测聚合，不适合余额、库存、订单提交。Redis 内存写加异步复制不能自动满足持久队列语义。</p><h2 id="_6-refresh-ahead" tabindex="-1">6. Refresh Ahead <a class="header-anchor" href="#_6-refresh-ahead" aria-label="Permalink to &quot;6. Refresh Ahead&quot;">​</a></h2><p>在 TTL 到期前异步刷新热门 key，使用户不承担 miss 延迟。刷新条件可以基于剩余 TTL、访问频率和刷新成本。</p><p>风险：预测错误会刷新冷数据；大量 key 同时接近到期造成后台雪崩；刷新失败如果不断续旧值会长期陈旧。需要 jitter、并发限制、最大 stale 窗口和刷新错误指标。</p><h2 id="_7-多级缓存结构" tabindex="-1">7. 多级缓存结构 <a class="header-anchor" href="#_7-多级缓存结构" aria-label="Permalink to &quot;7. 多级缓存结构&quot;">​</a></h2><p>常见层级：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;进程内 L1&quot;] --&gt; B[&quot;共享 Redis L2&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;数据库 / 服务事实源&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D[&quot;CDN / Edge&quot;] --&gt; A</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><table tabindex="0"><thead><tr><th>层</th><th style="text-align:right;">延迟</th><th>一致性范围</th><th style="text-align:right;">容量</th><th>典型失效</th></tr></thead><tbody><tr><td>浏览器/客户端</td><td style="text-align:right;">最低</td><td>单用户设备</td><td style="text-align:right;">小</td><td>Cache-Control/版本 URL</td></tr><tr><td>CDN/Edge</td><td style="text-align:right;">低</td><td>多区域共享</td><td style="text-align:right;">大</td><td>TTL、purge、surrogate key</td></tr><tr><td>进程内 L1</td><td style="text-align:right;">微秒级</td><td>单进程</td><td style="text-align:right;">很小</td><td>TTL、事件广播、版本 key</td></tr><tr><td>Redis L2</td><td style="text-align:right;">网络毫秒内</td><td>应用实例共享</td><td style="text-align:right;">中</td><td>delete/TTL/event</td></tr><tr><td>数据库</td><td style="text-align:right;">较高</td><td>权威事务</td><td style="text-align:right;">大</td><td>不作为缓存失效</td></tr></tbody></table><p>L1 命中不会访问 Redis，因此只删 L2 不能让所有进程立即一致。可用短 L1 TTL、失效 pub/sub/stream 或版本 key。Pub/Sub 断线期间可能漏消息，重连后要通过版本/TTL 收敛。</p><h2 id="_8-浏览器和-cdn-的-http-缓存" tabindex="-1">8. 浏览器和 CDN 的 HTTP 缓存 <a class="header-anchor" href="#_8-浏览器和-cdn-的-http-缓存" aria-label="Permalink to &quot;8. 浏览器和 CDN 的 HTTP 缓存&quot;">​</a></h2><p>HTTP 缓存与 Redis 不同。<code>Cache-Control: private</code> 限制共享缓存，<code>public</code> 允许；<code>max-age</code> 控制新鲜期，<code>s-maxage</code> 可覆盖共享缓存；<code>no-store</code> 禁止存储；验证器 <code>ETag</code>/<code>Last-Modified</code> 支持 304。</p><p>含 Cookie 或用户数据的响应不能因为路径相同就公开缓存。<code>Vary</code> 声明表示随哪些请求头变化，但把高基数头放 Vary 会碎片化缓存。CDN cache key 必须包含租户/语言/授权所需维度，或完全不缓存私人响应。</p><p>静态资源使用内容 hash 文件名和长 immutable TTL；发布新内容产生新 URL，比全网 purge 更可靠。</p><h2 id="_9-缓存-key-与表示版本" tabindex="-1">9. 缓存 key 与表示版本 <a class="header-anchor" href="#_9-缓存-key-与表示版本" aria-label="Permalink to &quot;9. 缓存 key 与表示版本&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>product:v3:tenant:t_7:id:p_9:locale:zh-CN</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>key 包含影响表示的所有稳定输入：schema version、tenant、资源 ID、locale、权限分组/价格区域等。不要把原始 bearer token 或敏感 PII 放 key。权限个性化维度太多时，缓存公共基础数据，在应用层做授权裁剪。</p><p>schema 变化用版本前缀隔离旧值，避免新代码解析旧 JSON。版本切换后旧 key 等 TTL 自然淘汰，防止 <code>KEYS product:*</code> 扫描删除生产集群。</p><h2 id="_10-序列化、压缩与大值" tabindex="-1">10. 序列化、压缩与大值 <a class="header-anchor" href="#_10-序列化、压缩与大值" aria-label="Permalink to &quot;10. 序列化、压缩与大值&quot;">​</a></h2><p>JSON 易调试但字段名占空间、类型演进需规则；Protobuf 等二进制更紧凑但要求 schema 管理。压缩减少网络/内存，却增加 CPU 和尾延迟；小值压缩可能变大。以真实分布 benchmark，不用单样本。</p><p>缓存只返回完整大对象会造成网络放大。可按稳定访问边界拆分，但避免 N+1。单 key 大值使 Redis 单线程命令、复制和删除成本增加。</p><h2 id="_11-空值与错误缓存" tabindex="-1">11. 空值与错误缓存 <a class="header-anchor" href="#_11-空值与错误缓存" aria-label="Permalink to &quot;11. 空值与错误缓存&quot;">​</a></h2><p>数据库确定不存在可缓存短期 sentinel，防止反复查询；sentinel 必须与“缓存 miss”和“查询失败”区分。创建对象后删除 negative cache。</p><p>不得把 500、timeout、权限拒绝当普通空值长缓存。错误缓存可能在依赖恢复后继续拒绝用户，或把一个主体的 403 泄漏给另一主体。若对过载错误做短期抑制，key 包含安全范围并有极短 TTL。</p><h2 id="_12-singleflight-与请求合并" tabindex="-1">12. Singleflight 与请求合并 <a class="header-anchor" href="#_12-singleflight-与请求合并" aria-label="Permalink to &quot;12. Singleflight 与请求合并&quot;">​</a></h2><p>同进程可让同 key miss 只由一个 goroutine 回源，其他等待；跨实例用 Redis 短锁或后台刷新，但不能让锁失败阻止正确回源。</p><p>singleflight 共享结果和错误，要绑定合理 deadline：最早取消的请求不应取消所有等待者；最长请求也不能让回源无限运行。热点 key 可直接预热或 stale-while-revalidate。</p><h2 id="_13-stale-while-revalidate-与-stale-if-error" tabindex="-1">13. Stale-while-revalidate 与 stale-if-error <a class="header-anchor" href="#_13-stale-while-revalidate-与-stale-if-error" aria-label="Permalink to &quot;13. Stale-while-revalidate 与 stale-if-error&quot;">​</a></h2><p>缓存同时保存 fresh deadline 和 hard deadline：fresh 前直接返回；fresh 后一个 worker 刷新，其他请求暂时返回旧值；hard 后必须回源或失败。</p><p>适合商品描述、配置展示，不适合账户余额或撤权。每类数据声明最大陈旧时长。依赖故障时允许 stale-if-error 能提高可用性，但响应/指标应能区分 stale。</p><h2 id="_14-应用案例一-商品详情" tabindex="-1">14. 应用案例一：商品详情 <a class="header-anchor" href="#_14-应用案例一-商品详情" aria-label="Permalink to &quot;14. 应用案例一：商品详情&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>读 QPS 2 万，写 QPS 20；95% 商品访问集中在 5%；价格允许最多陈旧 10 秒，库存只作展示提示，结算事务重新校验。</p><h3 id="方案" tabindex="-1">方案 <a class="header-anchor" href="#方案" aria-label="Permalink to &quot;方案&quot;">​</a></h3><ol><li>CDN 缓存公开图片和静态描述，资源 URL 内容 hash。</li><li>Redis L2 用 Cache Aside，key 带 tenant、locale、schema v3，TTL 5 分钟 ±20% jitter。</li><li>进程 L1 TTL 2 秒，失效事件含 product ID/version。</li><li>数据库提交商品更新与 outbox；consumer 删除 L2 并广播 L1 失效。</li><li>热点 miss 用 singleflight；数据库超时且旧值未超过 hard 10 秒时返回 stale。</li><li>结算读取数据库/库存系统，不相信缓存 stock_hint。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>记录 L1/L2 hit、回源 QPS、stale ratio、填充耗时和版本差。更新商品后 10 秒内所有层收敛；失效 consumer 停止时 TTL 仍最终收敛。</p><h3 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>关闭 Redis：L1 短期命中，其余经限流回源；超过数据库预算的请求快速降级，不无限重试。模拟热点 key 过期，singleflight 限制每实例一个回源，但全实例并发仍需数据库保护和预刷新。</p><h2 id="_15-应用案例二-授权元数据" tabindex="-1">15. 应用案例二：授权元数据 <a class="header-anchor" href="#_15-应用案例二-授权元数据" aria-label="Permalink to &quot;15. 应用案例二：授权元数据&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>权限决策 p99 &lt; 30 ms；角色变更必须 5 秒内生效；管理员撤权风险高；多租户隔离。</p><h3 id="方案-1" tabindex="-1">方案 <a class="header-anchor" href="#方案-1" aria-label="Permalink to &quot;方案&quot;">​</a></h3><ol><li>事实权限保存在数据库/策略服务，缓存 key 包含 tenant、subject、policy version。</li><li>普通读 Cache Aside，TTL 5 秒；策略发布提升全局 version，使旧 key 不再命中。</li><li>高风险管理员动作强制读取当前策略或要求短期提权，不接受 stale。</li><li>撤权事务写 outbox，消费者删除 L2 并广播 L1。</li><li>缓存故障时默认拒绝高风险操作；普通只读可按业务定义降级。</li></ol><h3 id="输出与验证-1" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证-1" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>跨租户 key 不重用；撤权事件丢失时 5 秒 TTL 收敛；策略 version 切换后旧缓存无法影响决策。审计记录实际使用的策略版本和缓存状态。</p><h3 id="失败注入-1" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入-1" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>暂停失效消费者并撤销管理员，验证高风险接口仍不会用陈旧缓存放行。若 L1 TTL 被误设 5 分钟，测试应直接失败。</p><h2 id="_16-模式比较" tabindex="-1">16. 模式比较 <a class="header-anchor" href="#_16-模式比较" aria-label="Permalink to &quot;16. 模式比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>读 miss 谁处理</th><th>写路径</th><th>优点</th><th>主要风险</th></tr></thead><tbody><tr><td>Cache Aside</td><td>应用</td><td>DB 后删缓存</td><td>简单、按需缓存</td><td>竞态、重复实现</td></tr><tr><td>Read Through</td><td>缓存库/层</td><td>独立</td><td>集中 loader</td><td>隐藏回源与授权边界</td></tr><tr><td>Write Through</td><td>缓存层同步</td><td>两边协调</td><td>写后缓存热</td><td>跨系统原子性</td></tr><tr><td>Write Behind</td><td>异步</td><td>缓存先接受</td><td>合并写、低延迟</td><td>数据损失、背压、对账</td></tr><tr><td>Refresh Ahead</td><td>后台</td><td>事实源不变</td><td>热 key 少 miss</td><td>刷新冷数据、雪崩</td></tr></tbody></table><h2 id="_17-调试路径" tabindex="-1">17. 调试路径 <a class="header-anchor" href="#_17-调试路径" aria-label="Permalink to &quot;17. 调试路径&quot;">​</a></h2><ol><li>按层记录 hit/miss，不把 L1 hit 混入 Redis hit。</li><li>对 miss 分为冷启动、TTL、主动失效、eviction、连接失败和解析失败。</li><li>比较 cache latency、pool wait、source latency、fill cost 和端到端。</li><li>采样缓存 version 与数据库 version；不记录敏感正文。</li><li>查看 Redis evicted/expired、memory、hot key、network bytes。</li><li>检查失效队列 lag、失败、重放和消费幂等。</li><li>用负载测试验证 Redis 全失效、热点过期和数据库降级。</li></ol><h2 id="_18-生产边界" tabindex="-1">18. 生产边界 <a class="header-anchor" href="#_18-生产边界" aria-label="Permalink to &quot;18. 生产边界&quot;">​</a></h2><ul><li>缓存实例不与不可淘汰会话/队列混用同一 eviction 策略。</li><li>TTL 不是一致性的证明，只是陈旧上限的一部分。</li><li>缓存 key/日志不泄露 PII 和 token。</li><li>连接池、命令 timeout、重试预算和熔断明确。</li><li>预热受限速，不在发布时全量扫数据库。</li><li>缓存重建有容量估算和优先级。</li><li>删除/隐私请求覆盖缓存、CDN 和派生数据。</li></ul><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>为多租户商品详情实现 CDN + L1 + Redis L2 + PostgreSQL，支持商品更新、locale、负缓存、singleflight 和 stale-if-error。</p><p>验收：</p><ol><li>画出每种读写时序和事实来源。</li><li>更新后陈旧上限有自动测试。</li><li>关闭每一缓存层，核心正确性不变且回源不雪崩。</li><li>跨租户和权限个性化数据不会串 key。</li><li>观察 L1/L2 hit、fill、stale、eviction、失效 lag 和 DB QPS。</li><li>能解释为何余额、库存扣减和最终授权不由缓存决定。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://redis.io/solutions/caching/" target="_blank" rel="noreferrer">Redis caching solutions</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/develop/reference/eviction/" target="_blank" rel="noreferrer">Redis key eviction</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9111.html" target="_blank" rel="noreferrer">RFC 9111: HTTP Caching</a>（访问日期：2026-07-17）</li><li><a href="https://pkg.go.dev/golang.org/x/sync/singleflight" target="_blank" rel="noreferrer">Go singleflight package</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/transaction-iso.html" target="_blank" rel="noreferrer">PostgreSQL 18: Transaction Isolation</a>（访问日期：2026-07-17）</li></ul>`,87)])])}const b=e(l,[["render",n]]);export{u as __pageData,b as default};
